#!/usr/bin/env bash
# =============================================================================
#  Rust RCON Panel — Full Stack Installer v1.10.0
#  Installs: SteamCMD · Rust Server · Oxide · Plugins · Panel
#  Requires: Debian/Ubuntu Linux, root
# =============================================================================
set -euo pipefail

VERSION="1.10.0"
STEAM_USER="steam"
STEAM_HOME="/home/steam"
RUST_DIR="${STEAM_HOME}/rustserver"
PANEL_DIR="${STEAM_HOME}/rcon-panel"
STEAMCMD_DIR="${STEAM_HOME}/steamcmd"
SERVICE_PANEL="rust-rcon-panel"
SERVICE_RUST="rust-server"
RUST_APP_ID="258550"

# Component toggles (all on by default)
INST_STEAMCMD=1
INST_RUST=1
INST_OXIDE=1
INST_PLUGINS=1
INST_PANEL=1

# SSL / HTTPS  (0=none 1=self-signed 2=custom 3=letsencrypt)
SSL_MODE=1
SSL_CERT=""
SSL_KEY=""
LE_DOMAIN=""
LE_EMAIL=""
WEB_PORT="443"
HTTP_PORT="80"

# ── Colors ────────────────────────────────────────────────────────────────────
E=$'\033'
R="${E}[0m"
BOLD="${E}[1m"
DIM="${E}[2m"
GRN="${E}[0;32m"
RED="${E}[0;31m"
YLW="${E}[1;33m"
CYN="${E}[0;36m"
WHT="${E}[1;37m"
ORG="${E}[38;5;208m"

# ── Animated skull spinner ────────────────────────────────────────────────────
_SPIN_PID=""
_SPIN_MSG=""
_SKULL_EYES=("(o.o)" "(-.-)" "(@.@)" "(~.~)" "(*.*)" "(°.°)" "(:.:)" "(>.>)")
_SPIN_CHARS=(⠋ ⠙ ⠹ ⠸ ⠼ ⠴ ⠦ ⠧ ⠇ ⠏)

spin_start() {
  _SPIN_MSG="$1"
  ( i=0
    while true; do
      ey="${_SKULL_EYES[$((i % 8))]}"
      sp="${_SPIN_CHARS[$((i % 10))]}"
      printf "\r  ${ORG}%s${R} ${DIM}%s${R} %s " "$ey" "$sp" "$_SPIN_MSG"
      i=$((i + 1))
      sleep 0.08
    done
  ) &
  _SPIN_PID=$!
}

spin_stop() {
  [[ -n "$_SPIN_PID" ]] && { kill "$_SPIN_PID" 2>/dev/null; wait "$_SPIN_PID" 2>/dev/null || true; _SPIN_PID=""; }
  printf "\r  ${GRN}(✓.✓)${R}  %-64s\n" "${1:-$_SPIN_MSG}"
}

spin_fail() {
  [[ -n "$_SPIN_PID" ]] && { kill "$_SPIN_PID" 2>/dev/null; wait "$_SPIN_PID" 2>/dev/null || true; _SPIN_PID=""; }
  printf "\r  ${RED}(x.x)${R}  %-64s\n" "${1:-$_SPIN_MSG}"
}

die() { spin_fail "$*"; exit 1; }
info() { printf "  ${CYN}→${R}  %s\n" "$*"; }

# ── Banner ────────────────────────────────────────────────────────────────────
show_banner() {
  clear
  printf "${ORG}"
  printf '  ╔══════════════════════════════════════════════════════════╗\n'
  printf '  ║                                                          ║\n'
  printf '  ║    .-.      R U S T   R C O N   P A N E L               ║\n'
  printf "  ║   (☠.☠)     Full Stack Installer  v%-6s               ║\n" "$VERSION"
  printf '  ║    )=(                                                   ║\n'
  printf '  ║   /   \     SteamCMD · Rust · Oxide · Plugins · Panel   ║\n'
  printf '  ║                                                          ║\n'
  printf '  ╚══════════════════════════════════════════════════════════╝\n'
  printf "${R}\n"
  printf "  ${DIM}Debian/Ubuntu · root required${R}\n\n"
}

# ── Checkbox TUI ──────────────────────────────────────────────────────────────
_draw_cb() {
  local title="$1" cur="$2" names_ref="$3" descs_ref="$4" sel_ref="$5"
  local -n _dcn="$names_ref" _dcd="$descs_ref" _dcs="$sel_ref"
  printf "\n  ${WHT}%s${R}\n\n" "$title"
  for ((i=0; i<${#_dcn[@]}; i++)); do
    local box="${DIM}[ ]${R}"; [[ "${_dcs[$i]}" == "1" ]] && box="${GRN}[✓]${R}"
    if ((i == cur)); then
      printf "  ${ORG}▶${R} %b ${BOLD}%-28s${R}  ${DIM}%s${R}\n" "$box" "${_dcn[$i]}" "${_dcd[$i]}"
    else
      printf "    %b %-28s  ${DIM}%s${R}\n" "$box" "${_dcn[$i]}" "${_dcd[$i]}"
    fi
  done
  printf "\n  ${DIM}↑/↓  navigate    SPACE  toggle    ENTER  confirm${R}\n"
}

_checkboxes() {
  local title="$1" names_ref="$2" descs_ref="$3" sel_ref="$4"
  local -n _cb_n="$names_ref" _cb_s="$sel_ref"
  local count=${#_cb_n[@]} cur=0
  local lines=$((count + 5))
  tput civis 2>/dev/null || true
  _draw_cb "$title" $cur "$names_ref" "$descs_ref" "$sel_ref"
  while true; do
    local key; IFS= read -rsn1 key 2>/dev/null || true
    if [[ "$key" == $'\x1b' ]]; then
      local seq; IFS= read -rsn2 -t 0.05 seq 2>/dev/null || true
      case "$seq" in
        '[A') ((cur > 0)) && ((cur--)) || true ;;
        '[B') ((cur < count - 1)) && ((cur++)) || true ;;
      esac
    elif [[ "$key" == ' ' ]]; then
      _cb_s[$cur]=$(( 1 - _cb_s[$cur] ))
    elif [[ -z "$key" ]]; then
      break
    fi
    printf "\033[%dA" $lines
    _draw_cb "$title" $cur "$names_ref" "$descs_ref" "$sel_ref"
  done
  tput cnorm 2>/dev/null || true; echo
}

# ── Radio TUI ─────────────────────────────────────────────────────────────────
_draw_radio() {
  local title="$1" cur="$2" names_ref="$3" descs_ref="$4"
  local -n _drn="$names_ref" _drd="$descs_ref"
  printf "\n  ${WHT}%s${R}\n\n" "$title"
  for ((i=0; i<${#_drn[@]}; i++)); do
    local dot="${DIM}( )${R}"; ((i == cur)) && dot="${GRN}(●)${R}"
    if ((i == cur)); then
      printf "  ${ORG}▶${R} %b ${BOLD}%-28s${R}  ${DIM}%s${R}\n" "$dot" "${_drn[$i]}" "${_drd[$i]}"
    else
      printf "    %b %-28s  ${DIM}%s${R}\n" "$dot" "${_drn[$i]}" "${_drd[$i]}"
    fi
  done
  printf "\n  ${DIM}↑/↓  navigate    ENTER  select${R}\n"
}

_radio() {
  local title="$1" names_ref="$2" descs_ref="$3" result_ref="$4"
  local -n _r_n="$names_ref"
  local count=${#_r_n[@]}
  local cur="${!result_ref}"
  local lines=$((count + 5))
  tput civis 2>/dev/null || true
  _draw_radio "$title" $cur "$names_ref" "$descs_ref"
  while true; do
    local key; IFS= read -rsn1 key 2>/dev/null || true
    if [[ "$key" == $'\x1b' ]]; then
      local seq; IFS= read -rsn2 -t 0.05 seq 2>/dev/null || true
      case "$seq" in
        '[A') ((cur > 0)) && ((cur--)) || true ;;
        '[B') ((cur < count - 1)) && ((cur++)) || true ;;
      esac
    elif [[ -z "$key" ]]; then
      break
    fi
    printf "\033[%dA" $lines
    _draw_radio "$title" $cur "$names_ref" "$descs_ref"
  done
  tput cnorm 2>/dev/null || true
  printf -v "$result_ref" '%d' "$cur"; echo
}

# ── Prompt helpers ────────────────────────────────────────────────────────────
ask() {
  local var="$1" prompt="$2" default="${3:-}" mode="${4:-}"
  printf "  ${CYN}?${R} ${BOLD}%s${R}" "$prompt"
  [[ -n "$default" ]] && printf "  ${DIM}[%s]${R}" "$default"
  printf ": "
  local val
  if [[ "$mode" == "secret" ]]; then IFS= read -rs val; echo
  else IFS= read -r val; fi
  [[ -z "$val" ]] && val="$default"
  printf -v "$var" '%s' "$val"
}

gen_pw()   { openssl rand -base64 18 | tr -d '/+=' | head -c 20; }
gen_seed() { echo $((RANDOM * RANDOM % 2147483647)); }

# ── Preflight ─────────────────────────────────────────────────────────────────
check_root()   { [[ $EUID -eq 0 ]] || die "Run as root: sudo bash install.sh"; }
check_os()     { command -v apt-get &>/dev/null || die "Requires Debian/Ubuntu (apt)"; PKG_MGR="apt"; }
check_python() { python3 --version &>/dev/null || die "python3 not found"; }

# ── Config gathering ──────────────────────────────────────────────────────────
gather_config() {
  printf "\n  ${WHT}─── Rust Server ─────────────────────────────────────────────${R}\n\n"
  ask SERVER_NAME "Server display name"           "My Rust Server"
  ask SERVER_DESC "Server description"            "A Rust server"
  ask SERVER_PORT "Game port"                     "28015"
  ask RCON_PORT   "RCON WebSocket port"           "28016"
  local auto_rcon; auto_rcon=$(gen_pw)
  ask RCON_PASS   "RCON password  (blank=auto)"   "" secret
  [[ -z "$RCON_PASS" ]] && RCON_PASS="$auto_rcon" && info "RCON password: ${BOLD}${RCON_PASS}${R}"
  ask WORLD_SIZE  "World size (1000–6000)"        "3000"
  local auto_seed; auto_seed=$(gen_seed)
  ask WORLD_SEED  "World seed  (blank=random)"    ""
  [[ -z "$WORLD_SEED" ]] && WORLD_SEED="$auto_seed" && info "World seed: ${BOLD}${WORLD_SEED}${R}"
  ask MAX_PLAYERS "Max players"                   "50"

  printf "\n  ${WHT}─── Panel ───────────────────────────────────────────────────${R}\n\n"
  local auto_web; auto_web=$(gen_pw)
  ask WEB_PASS "Panel password  (blank=auto)" "" secret
  [[ -z "$WEB_PASS" ]] && WEB_PASS="$auto_web" && info "Panel password: ${BOLD}${WEB_PASS}${R}"

  printf "\n  ${WHT}─── Paths ───────────────────────────────────────────────────${R}\n\n"
  ask RUST_DIR   "Rust server dir"  "$RUST_DIR"
  ask PANEL_DIR  "Panel dir"        "$PANEL_DIR"
  STEAMCMD_DIR="${STEAM_HOME}/steamcmd"
}

# ── SSL config ────────────────────────────────────────────────────────────────
gather_ssl() {
  local ssl_names=("None — HTTP only" "Self-signed (auto-generated)" "Custom certificate" "Let's Encrypt (ACME)")
  local ssl_descs=("Not recommended" "Browser will warn — fine for LAN" "Provide cert + key paths" "Requires public domain + port 80")
  _radio "SSL / TLS:" ssl_names ssl_descs SSL_MODE

  case $SSL_MODE in
    0) WEB_PORT="80"; HTTP_PORT="" ;;
    1) ask WEB_PORT "HTTPS port" "443"; HTTP_PORT="80"
       SSL_CERT="${PANEL_DIR}/ssl/cert.pem"; SSL_KEY="${PANEL_DIR}/ssl/key.pem" ;;
    2) ask SSL_CERT "Certificate path (.pem)" "/etc/ssl/certs/panel.pem"
       ask SSL_KEY  "Key path (.pem)"          "/etc/ssl/private/panel.key"
       ask WEB_PORT "HTTPS port" "443"; HTTP_PORT="80" ;;
    3) ask LE_DOMAIN "Domain name" ""
       ask LE_EMAIL  "Email (expiry notices)" ""
       WEB_PORT="443"; HTTP_PORT="80"
       SSL_CERT="/etc/letsencrypt/live/${LE_DOMAIN}/fullchain.pem"
       SSL_KEY="/etc/letsencrypt/live/${LE_DOMAIN}/privkey.pem" ;;
  esac
}

# ── Summary / confirm ─────────────────────────────────────────────────────────
show_summary() {
  printf "\n  ${WHT}─── Summary ─────────────────────────────────────────────────${R}\n\n"
  local comps=""
  [[ $INST_STEAMCMD -eq 1 ]] && comps+="SteamCMD "
  [[ $INST_RUST     -eq 1 ]] && comps+="Rust "
  [[ $INST_OXIDE    -eq 1 ]] && comps+="Oxide "
  [[ $INST_PLUGINS  -eq 1 ]] && comps+="Plugins "
  [[ $INST_PANEL    -eq 1 ]] && comps+="Panel "
  printf "  Components : %s\n" "$comps"
  printf "  Server     : %s  (port %s, RCON %s)\n" "$SERVER_NAME" "$SERVER_PORT" "$RCON_PORT"
  case $SSL_MODE in
    0) printf "  Panel      : http://…:%s\n" "$WEB_PORT" ;;
    1) printf "  Panel      : https://…:%s  (self-signed)\n" "$WEB_PORT" ;;
    2) printf "  Panel      : https://…:%s  (custom cert)\n" "$WEB_PORT" ;;
    3) printf "  Panel      : https://%s\n" "$LE_DOMAIN" ;;
  esac
  printf "  World      : size=%s  seed=%s  maxplayers=%s\n\n" "$WORLD_SIZE" "$WORLD_SEED" "$MAX_PLAYERS"
  local confirm; ask confirm "Proceed? (yes/no)" "yes"
  [[ "$confirm" == "yes" || "$confirm" == "y" ]] || { printf "  Aborted.\n"; exit 0; }
  echo
}

# ── System deps ───────────────────────────────────────────────────────────────
install_system_deps() {
  dpkg --add-architecture i386 2>/dev/null || true
  apt-get update -qq 2>/dev/null
  local pkgs="curl wget unzip tar lib32gcc-s1 libgdiplus python3 python3-aiohttp python3-cryptography openssl"
  [[ $SSL_MODE -eq 3 ]] && pkgs+=" certbot"
  apt-get install -y -q $pkgs >/dev/null 2>&1
}

# ── Steam user ────────────────────────────────────────────────────────────────
setup_steam_user() {
  if ! id "$STEAM_USER" &>/dev/null; then useradd -m -s /bin/bash "$STEAM_USER"; fi
  STEAM_HOME=$(getent passwd "$STEAM_USER" | cut -d: -f6)
  RUST_DIR="${RUST_DIR/#\/home\/steam/$STEAM_HOME}"
  PANEL_DIR="${PANEL_DIR/#\/home\/steam/$STEAM_HOME}"
  STEAMCMD_DIR="${STEAMCMD_DIR/#\/home\/steam/$STEAM_HOME}"
}

# ── SteamCMD ──────────────────────────────────────────────────────────────────
install_steamcmd() {
  [[ -f "${STEAMCMD_DIR}/steamcmd.sh" ]] && return
  mkdir -p "$STEAMCMD_DIR"
  curl -sSL "https://steamcdn-a.akamaihd.net/client/installer/steamcmd_linux.tar.gz" \
    | tar -xz -C "$STEAMCMD_DIR"
  chown -R "${STEAM_USER}:${STEAM_USER}" "$STEAMCMD_DIR"
}

# ── Rust server ───────────────────────────────────────────────────────────────
install_rust() {
  mkdir -p "$RUST_DIR"
  chown "${STEAM_USER}:${STEAM_USER}" "$RUST_DIR"
  su -s /bin/bash "$STEAM_USER" -c \
    "${STEAMCMD_DIR}/steamcmd.sh +force_install_dir \"${RUST_DIR}\" \
      +login anonymous +app_update ${RUST_APP_ID} validate +quit" \
    >> /tmp/rust-install.log 2>&1
  [[ -f "${RUST_DIR}/RustDedicated" ]] || die "Rust binary not found — check /tmp/rust-install.log"
}

# ── Oxide/uMod ────────────────────────────────────────────────────────────────
install_oxide() {
  local url="https://github.com/OxideMod/Oxide.Rust/releases/latest/download/Oxide.Rust-linux.zip"
  local tmp="/tmp/oxide_rust.zip"
  curl -sSL "$url" -o "$tmp" 2>/dev/null || wget -q "$url" -O "$tmp" || die "Failed to download Oxide"
  unzip -o "$tmp" -d "$RUST_DIR" >/dev/null
  rm -f "$tmp"
  chown -R "${STEAM_USER}:${STEAM_USER}" "$RUST_DIR"
}

# ── Rust startup script ───────────────────────────────────────────────────────
configure_rust_server() {
  local qport=$(( SERVER_PORT + 1 ))
  cat > "${RUST_DIR}/start.sh" << STARTSH
#!/bin/bash
cd "${RUST_DIR}"
exec ./RustDedicated \\
  -batchmode -nographics \\
  -server.ip 0.0.0.0 -server.port ${SERVER_PORT} -server.queryport ${qport} \\
  -rcon.ip 0.0.0.0 -rcon.port ${RCON_PORT} -rcon.password "${RCON_PASS}" -rcon.web 1 \\
  -server.identity my_server_identity \\
  -server.hostname "${SERVER_NAME}" -server.description "${SERVER_DESC}" \\
  -server.worldsize ${WORLD_SIZE} -server.seed ${WORLD_SEED} \\
  -server.maxplayers ${MAX_PLAYERS} +server.saveinterval 300
STARTSH
  chmod +x "${RUST_DIR}/start.sh"
  chown "${STEAM_USER}:${STEAM_USER}" "${RUST_DIR}/start.sh"
}

# ── SSL / TLS setup ───────────────────────────────────────────────────────────
configure_ssl() {
  [[ $SSL_MODE -eq 0 ]] && return

  case $SSL_MODE in
    1)  # Self-signed
      mkdir -p "${PANEL_DIR}/ssl"
      openssl req -x509 -newkey rsa:4096 \
        -keyout "${SSL_KEY}" -out "${SSL_CERT}" \
        -days 3650 -nodes \
        -subj "/CN=rust-rcon-panel/O=RustPanel/C=US" 2>/dev/null
      chmod 600 "${SSL_KEY}"
      chown -R root:root "${PANEL_DIR}/ssl"
      ;;
    2)  # Custom — validate paths
      [[ -f "$SSL_CERT" ]] || die "Certificate not found: $SSL_CERT"
      [[ -f "$SSL_KEY"  ]] || die "Key not found: $SSL_KEY"
      ;;
    3)  # Let's Encrypt
      [[ -n "$LE_DOMAIN" ]] || die "Domain required for Let's Encrypt"
      systemctl stop "${SERVICE_PANEL}" 2>/dev/null || true
      certbot certonly --standalone \
        -d "$LE_DOMAIN" --agree-tos --non-interactive --email "${LE_EMAIL}" \
        || die "Let's Encrypt certificate request failed"
      cat > "/etc/letsencrypt/renewal-hooks/deploy/rust-rcon-panel.sh" << 'HOOK'
#!/bin/bash
systemctl restart rust-rcon-panel
HOOK
      chmod +x "/etc/letsencrypt/renewal-hooks/deploy/rust-rcon-panel.sh"
      ;;
  esac

  # Write SSL section into config.json
  local ssl_mode_str
  case $SSL_MODE in 1) ssl_mode_str="self_signed" ;; 2) ssl_mode_str="custom" ;; 3) ssl_mode_str="letsencrypt" ;; esac
  python3 - << PYEOF
import json
cfg_path = '${PANEL_DIR}/config.json'
with open(cfg_path) as f: cfg = json.load(f)
cfg['web']['port'] = int('${WEB_PORT}')
cfg['web']['http_port'] = int('${HTTP_PORT}') if '${HTTP_PORT}' else 80
cfg['web']['ssl'] = {'mode': '${ssl_mode_str}', 'cert': '${SSL_CERT}', 'key': '${SSL_KEY}'}
with open(cfg_path, 'w') as f: json.dump(cfg, f, indent=2)
PYEOF
}

# ── BLOB FUNCTIONS — do not edit manually ────────────────────────────────────
deploy_panel() {
  info "Deploying RCON panel to ${PANEL_DIR}..."
  mkdir -p "${PANEL_DIR}/static"

  # ── app.py ───────────────────────────────────────────────────────────────
  python3 -c "
import base64, sys
data = b''''''
sys.stdout.buffer.write(base64.b64decode(data))
" > "${PANEL_DIR}/app.py"
  ok "app.py deployed"

  # ── favicon.svg ──────────────────────────────────────────────────────────
  cat > "${PANEL_DIR}/static/favicon.svg" << 'SVGEOF'
<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 32 32">
<rect width="32" height="32" rx="6" fill="#1a1c20"/>
<ellipse cx="16" cy="13" rx="10" ry="10" fill="#4fc3f7"/>
<circle cx="11.5" cy="12" r="2.5" fill="#1a1c20"/>
<circle cx="20.5" cy="12" r="2.5" fill="#1a1c20"/>
<rect x="11.5" y="22" width="3" height="6" rx="1.5" fill="#4fc3f7"/>
<rect x="17.5" y="22" width="3" height="6" rx="1.5" fill="#4fc3f7"/>
<rect x="9.5" y="27" width="13" height="2.5" rx="1.2" fill="#4fc3f7" opacity=".4"/>
</svg>
SVGEOF

  # ── Secure config + encrypted profile ────────────────────────────────────
  local img_path="${RUST_DIR}/oxide/data/MapRenderer/map.png"
  python3 - << PYEOF
import os, json, base64, hashlib
from cryptography.fernet import Fernet

panel_dir  = '${PANEL_DIR}'
rcon_host  = '127.0.0.1'
rcon_port  = ${RCON_PORT}
rcon_pass  = '${RCON_PASS}'
web_port   = ${WEB_PORT}
web_pass   = '${WEB_PASS}'
world_size = ${WORLD_SIZE}
world_seed = ${WORLD_SEED}
img_path   = '${img_path}'
server_name = '${SERVER_NAME}'

# Generate Fernet key
key = Fernet.generate_key()
key_path = os.path.join(panel_dir, '.secret_key')
with open(key_path, 'wb') as f:
    f.write(key)
os.chmod(key_path, 0o600)
fernet = Fernet(key)

# Encrypt RCON password
rcon_enc = 'enc:' + fernet.encrypt(rcon_pass.encode()).decode()

# Hash web panel password
salt = os.urandom(16).hex()
dk   = hashlib.pbkdf2_hmac('sha256', web_pass.encode(), salt.encode(), 260_000)
web_hash = 'pbkdf2:' + salt + ':' + base64.b64encode(dk).decode()

# config.json — no rcon section, no plaintext credentials
config = {
    'web': {'host': '0.0.0.0', 'port': web_port, 'password': web_hash},
    'map': {'world_size': world_size, 'seed': world_seed,
            'image_url': '', 'image_path': img_path}
}
with open(os.path.join(panel_dir, 'config.json'), 'w') as f:
    json.dump(config, f, indent=2)

# profiles.json — encrypted RCON credentials
profile_id = os.urandom(6).hex()
profiles = [{'id': profile_id, 'name': server_name,
             'host': rcon_host, 'port': rcon_port, 'password': rcon_enc}]
with open(os.path.join(panel_dir, 'profiles.json'), 'w') as f:
    json.dump(profiles, f, indent=2)

print('Panel config written (all passwords secured)')
PYEOF

  chown -R "${STEAM_USER}:${STEAM_USER}" "$PANEL_DIR"
  ok "Panel deployed and configured"
}

# ── Oxide plugins ─────────────────────────────────────────────────────────────

deploy_plugins() {
  local plugin_dir="${RUST_DIR}/oxide/plugins"
  mkdir -p "$plugin_dir"

  # ── MapRenderer.cs ───────────────────────────────────────────────────────
  info "Deploying MapRenderer plugin..."
  python3 -c "
import base64, sys
data = b''''''
sys.stdout.buffer.write(base64.b64decode(data))
" > "${plugin_dir}/MapRenderer.cs"

  local map_cfg="${RUST_DIR}/oxide/config/MapRenderer.json"
  local img_path="${RUST_DIR}/oxide/data/MapRenderer/map.png"
  mkdir -p "$(dirname "$map_cfg")" "$(dirname "$img_path")"
  if [ ! -f "$map_cfg" ]; then
    echo "{\"output_path\": \"${img_path}\"}" > "$map_cfg"
  fi
  ok "MapRenderer.cs deployed"

  # ── PlayerLocation.cs ────────────────────────────────────────────────────
  info "Getting PlayerLocation plugin..."
  if curl -fsSL "https://umod.org/plugins/PlayerLocation.cs" \
       -o "${plugin_dir}/PlayerLocation.cs" 2>/dev/null \
     || wget -q "https://umod.org/plugins/PlayerLocation.cs" \
       -O "${plugin_dir}/PlayerLocation.cs" 2>/dev/null; then
    ok "PlayerLocation.cs downloaded"
  else
    warn "Download failed — embedding bundled version"
    cat > "${plugin_dir}/PlayerLocation.cs" << 'PLOC_EOF'
using System;
using System.Collections.Generic;
using Oxide.Core;
using Oxide.Core.Libraries.Covalence;
using UnityEngine;

namespace Oxide.Plugins
{
    [Info("Player Location", "seacowz", "0.1.7")]
    [Description("Find the location of players on the server")]
    public class PlayerLocation : CovalencePlugin
    {
        private const string permAdmin = "playerlocation.admin";
        void Init() { permission.RegisterPermission(permAdmin, this); }

        [Command("location"), Permission("playerlocation.admin")]
        void CmdLocation(IPlayer iplayer, string command, string[] args)
        {
            bool any = false;
            foreach (var p in players.Connected)
            {
                var bp = p.Object as BasePlayer;
                if (bp == null) continue;
                var pos = bp.transform.position;
                var grid = PhoneController.PositionToGridCoord(pos);
                iplayer.Reply($"{p.Id} {p.Name}: {grid}, {pos.x:F1}, {pos.z:F1}");
                any = true;
            }
            if (!any) iplayer.Reply("No players found.");
        }
    }
}
PLOC_EOF
  fi

  chown -R "${STEAM_USER}:${STEAM_USER}" "$RUST_DIR"
}

# ── Systemd services ──────────────────────────────────────────────────────────

# ── Systemd services ──────────────────────────────────────────────────────────
install_services() {
  # Rust dedicated server
  cat > "/etc/systemd/system/${SERVICE_RUST}.service" << SVC
[Unit]
Description=Rust Dedicated Game Server
After=network.target

[Service]
Type=simple
User=${STEAM_USER}
Group=${STEAM_USER}
WorkingDirectory=${RUST_DIR}
ExecStart=${RUST_DIR}/start.sh
Restart=on-failure
RestartSec=30
KillSignal=SIGINT
TimeoutStopSec=120
StandardOutput=journal
StandardError=journal

[Install]
WantedBy=multi-user.target
SVC

  # RCON panel
  cat > "/etc/systemd/system/${SERVICE_PANEL}.service" << SVC
[Unit]
Description=Rust RCON Web Panel
After=network.target

[Service]
Type=simple
WorkingDirectory=${PANEL_DIR}
ExecStart=/usr/bin/python3 ${PANEL_DIR}/app.py
Restart=always
RestartSec=5
StandardOutput=journal
StandardError=journal

[Install]
WantedBy=multi-user.target
SVC

  systemctl daemon-reload
  systemctl enable "${SERVICE_RUST}"  2>/dev/null || true
  systemctl enable "${SERVICE_PANEL}" 2>/dev/null || true
  systemctl restart "${SERVICE_PANEL}"
  sleep 2
  systemctl is-active "${SERVICE_PANEL}" >/dev/null \
    || { journalctl -u "${SERVICE_PANEL}" -n 30 --no-pager; die "Panel service failed to start"; }
  [[ $INST_RUST -eq 1 ]] && { systemctl start "${SERVICE_RUST}" 2>/dev/null || true; }
}

# ── Oxide permissions ─────────────────────────────────────────────────────────
grant_oxide_permissions() {
  [[ $INST_RUST -eq 0 || $INST_OXIDE -eq 0 ]] && return
  local attempts=18
  for i in $(seq 1 $attempts); do
    sleep 5
    python3 - << PYEOF 2>/dev/null && break
import asyncio, aiohttp, json
async def run():
    async with aiohttp.ClientSession() as s:
        async with s.ws_connect('ws://127.0.0.1:${RCON_PORT}/${RCON_PASS}',
                timeout=aiohttp.ClientTimeout(connect=3)) as ws:
            cmd = 'oxide.grant group admin playerlocation.admin'
            await ws.send_str(json.dumps({'Identifier':1,'Message':cmd,'Name':'installer'}))
            await asyncio.wait_for(ws.receive(), timeout=5)
asyncio.run(run())
PYEOF
  done
  return 0
}

# ── Summary ───────────────────────────────────────────────────────────────────
print_summary() {
  local ip; ip=$(hostname -I | awk '{print $1}')
  local panel_url
  case $SSL_MODE in
    0) panel_url="http://${ip}:${WEB_PORT}" ;;
    3) panel_url="https://${LE_DOMAIN}" ;;
    *) panel_url="https://${ip}:${WEB_PORT}" ;;
  esac
  printf "\n"
  printf "  ${GRN}╔══════════════════════════════════════════════════════════╗${R}\n"
  printf "  ${GRN}║  Installation complete — v%-6s                        ║${R}\n" "$VERSION"
  printf "  ${GRN}╚══════════════════════════════════════════════════════════╝${R}\n\n"
  printf "  ${BOLD}RCON Panel  :${R}  %s\n"   "$panel_url"
  printf "  ${BOLD}Password    :${R}  %s\n\n" "$WEB_PASS"
  printf "  ${BOLD}Rust Server :${R}  %s:%s\n" "$ip" "$SERVER_PORT"
  printf "  ${BOLD}RCON port   :${R}  %s\n"   "$RCON_PORT"
  printf "  ${BOLD}RCON pwd    :${R}  %s\n"   "$RCON_PASS"
  printf "  ${BOLD}World       :${R}  size=%s  seed=%s  max=%s\n\n" "$WORLD_SIZE" "$WORLD_SEED" "$MAX_PLAYERS"
  printf "  ${BOLD}Services    :${R}  systemctl {start|stop|status} %s\n" "$SERVICE_PANEL"
  printf "               systemctl {start|stop|status} %s\n" "$SERVICE_RUST"
  printf "  ${BOLD}Logs        :${R}  journalctl -u %s -f\n\n" "$SERVICE_PANEL"
  [[ $SSL_MODE -eq 1 ]] && printf "  ${YLW}Note:${R} Self-signed cert — add browser exception to proceed.\n\n"
  printf "  ${DIM}Map renders ~10s after Rust server starts.${R}\n\n"
}

# ── Main ──────────────────────────────────────────────────────────────────────
main() {
  check_root; check_os; check_python
  show_banner

  # ── Component selection ──
  local comp_names=("SteamCMD" "Rust Game Server" "Oxide / uMod" "MapRenderer plugin" "RCON Panel")
  local comp_descs=("Required for Rust download" "Dedicated server (~10 GB)" "Plugin framework (required)" "Map rendering in panel" "Web management interface")
  local comp_sel=($INST_STEAMCMD $INST_RUST $INST_OXIDE $INST_PLUGINS $INST_PANEL)
  _checkboxes "Select components to install:" comp_names comp_descs comp_sel
  INST_STEAMCMD=${comp_sel[0]}; INST_RUST=${comp_sel[1]}; INST_OXIDE=${comp_sel[2]}
  INST_PLUGINS=${comp_sel[3]};  INST_PANEL=${comp_sel[4]}

  # ── Gather config ──
  gather_config
  gather_ssl
  show_summary

  # ── Install ──
  spin_start "Installing system packages"
  install_system_deps
  spin_stop "System packages installed"

  spin_start "Setting up steam user"
  setup_steam_user
  spin_stop "Steam user ready"

  if [[ $INST_STEAMCMD -eq 1 ]]; then
    spin_start "Installing SteamCMD"
    install_steamcmd
    spin_stop "SteamCMD installed"
  fi

  if [[ $INST_RUST -eq 1 ]]; then
    spin_start "Downloading Rust server (~10 GB — this may take 15–30 min)"
    install_rust
    spin_stop "Rust dedicated server installed"
  fi

  if [[ $INST_OXIDE -eq 1 ]]; then
    spin_start "Installing Oxide / uMod"
    install_oxide
    spin_stop "Oxide / uMod installed"
  fi

  if [[ $INST_RUST -eq 1 ]]; then
    spin_start "Writing server startup script"
    configure_rust_server
    spin_stop "Startup script written"
  fi

  if [[ $INST_PANEL -eq 1 ]]; then
    spin_start "Deploying RCON panel"
    deploy_panel
    spin_stop "Panel deployed"
  fi

  if [[ $INST_PLUGINS -eq 1 ]]; then
    spin_start "Installing plugins"
    deploy_plugins
    spin_stop "Plugins installed"
  fi

  if [[ $INST_PANEL -eq 1 && $SSL_MODE -gt 0 ]]; then
    spin_start "Configuring SSL / TLS"
    configure_ssl
    spin_stop "SSL configured"
  fi

  spin_start "Installing and enabling systemd services"
  install_services
  spin_stop "Services enabled — autostart on boot active"

  if [[ $INST_RUST -eq 1 && $INST_OXIDE -eq 1 ]]; then
    spin_start "Waiting for Rust server + granting Oxide permissions"
    grant_oxide_permissions
    spin_stop "Oxide permissions granted"
  fi

  print_summary
}

main "$@"
